import Vue from "vue";
import Router from "vue-router";
Vue.use(Router);

export default new Router({
  routes: [
    {
      path: "/",
      name: "HelloWorld",
      component: () => import("@/components/HelloWorld")
    },
    {
      path: "/VR",
      name: "VR",
      component: () => import("@/components/VR")
    },
    {
      path: "/sand",
      name: "sand",
      component: () => import("@/components/sand")
    },
    {
      path: "/bear",
      name: "bear",
      component: () => import("@/components/bear")
    },
    {
      path: "/love",
      name: "love",
      component: () => import("@/components/love")
    },
    {
      path: "/robot",
      name: "robot",
      component: () => import("@/components/robot")
    },
    {
      path: "/earth",
      name: "earth",
      component: () => import("@/components/earth")
    }
  ]
});



